/**
 * @fileoverview Toggle helpers — pure utility functions.
 * @module module/Toggle/helpers
 */

/**
 * Resolve the label text for the current checked state.
 *
 * @param {boolean} checked — current checked state
 * @param {string|null} labelOn — label when on
 * @param {string|null} labelOff — label when off
 * @returns {string|null} resolved label or null
 */
export function resolveLabel(checked, labelOn, labelOff) {
    if (checked && labelOn) return labelOn;
    if (!checked && labelOff) return labelOff;
    return labelOn || labelOff || null;
}
